comments.body:
Adding some kind of override or path extension totally makes sense to me! As as in your example, we may only override the `/jobs` sub path to prevent cross API conflicts.

I suggest the following API changes:


```
diff --git a/dapr/proto/runtime/v1/dapr.proto b/dapr/proto/runtime/v1/dapr.proto
index 41b978a93..cd5b35e5f 100644
--- a/dapr/proto/runtime/v1/dapr.proto
+++ b/dapr/proto/runtime/v1/dapr.proto
@@ -1258,6 +1258,12 @@ message Job {
   // payload is the serialized job payload that will be sent to the recipient
   // when the job is triggered.
   google.protobuf.Any data = 6 [json_name = "data"];
+
+  // override route path is an optional string which overrides the route which
+  // would otherwise be the Job name.
+  // `/job/{name}` -> `/job/{override_route_path}`.
+  // If set, must be a non empty HTTP path complaint string.
+  optional string override_route_path = 7 [json_name = "overrideRoutePath"];
 }

 // ScheduleJobRequest is the message to create/schedule the job.
@@ -1344,4 +1350,4 @@ message ConversationResponse {

   // An array of results.
   repeated ConversationResult outputs = 2;
-}
\ No newline at end of file
+}
diff --git a/dapr/proto/scheduler/v1/scheduler.proto b/dapr/proto/scheduler/v1/scheduler.proto
index b765b7819..65e29b377 100644
--- a/dapr/proto/scheduler/v1/scheduler.proto
+++ b/dapr/proto/scheduler/v1/scheduler.proto
@@ -50,7 +50,13 @@ message Job {

 // TargetJob is the message used by the daprd sidecar to schedule a job
 // from an App.
-message TargetJob {}
+message TargetJob {
+  // override route path is an optional string which overrides the route which
+  // would otherwise be the Job name.
+  // `/job/{name}` -> `/job/{override_route_path}`.
+  // If set, must be a non empty HTTP path complaint string.
+  optional string override_route_path = 1;
+}

 // TargetActorReminder is the message used by the daprd sidecar to
 // schedule a job from an Actor Reminder.
```
